4	-- Description: UDP TX Engine Module
5	-- Note: UDP checksum checked in EthMac core
6	-------------------------------------------------------------------------------
7	-- This file is part of 'SLAC Firmware Standard Library'.
8	-- It is subject to the license terms in the LICENSE.txt file found in the
9	-- top-level directory of this distribution and at:
10	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
11	-- No part of 'SLAC Firmware Standard Library', including this file,
12	-- may be copied, modified, propagated, or distributed except according to
13	-- the terms contained in the LICENSE.txt file.
14	-------------------------------------------------------------------------------
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_unsigned.all;
19	use ieee.std_logic_arith.all;
20	
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiStreamPkg.all;
25	use surf.SsiPkg.all;
26	use surf.EthMacPkg.all;
27	
28	entity UdpEngineTx is
29	   generic (
30	      TPD_G          : time          := 1 ns;
31	      RST_POLARITY_G : sl            := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
32	      RST_ASYNC_G    : boolean       := false;
33	      -- UDP General Generic
34	      SIZE_G         : positive      := 1;
35	      TX_FLOW_CTRL_G : boolean       := true;  -- True: Blow off the UDP TX data if link down, False: Backpressure until TX link is up
36	      IS_CLIENT_G    : boolean       := false;
37	      PORT_G         : PositiveArray := (0 => 8192));
38	   port (
39	      -- Interface to IPV4 Engine
40	      obUdpMaster   : out AxiStreamMasterType;
41	      obUdpSlave    : in  AxiStreamSlaveType;
42	      -- Interface to User Application
43	      linkUp        : out slv(SIZE_G-1 downto 0);
44	      localMac      : in  slv(47 downto 0);
45	      localIp       : in  slv(31 downto 0);
46	      remotePort    : in  Slv16Array(SIZE_G-1 downto 0);
47	      remoteIp      : in  Slv32Array(SIZE_G-1 downto 0);
48	      remoteMac     : in  Slv48Array(SIZE_G-1 downto 0);
49	      ibMasters     : in  AxiStreamMasterArray(SIZE_G-1 downto 0);
50	      ibSlaves      : out AxiStreamSlaveArray(SIZE_G-1 downto 0);
51	      arpTabPos     : out Slv8Array(SIZE_G-1 downto 0);
52	      arpTabFound   : in  slv(SIZE_G-1 downto 0)        := (others => '0');
53	      arpTabIpAddr  : in  Slv32Array(SIZE_G-1 downto 0) := (others => (others => '0'));
54	      arpTabMacAddr : in  Slv48Array(SIZE_G-1 downto 0) := (others => (others => '0'));
55	      -- Interface to DHCP Engine
56	      obDhcpMaster  : in  AxiStreamMasterType           := AXI_STREAM_MASTER_INIT_C;
57	      obDhcpSlave   : out AxiStreamSlaveType;
58	      -- Clock and Reset
59	      clk           : in  sl;
60	      rst           : in  sl);
61	end UdpEngineTx;
62	
63	architecture rtl of UdpEngineTx is
64	
65	   constant PORT_C : Slv16Array(SIZE_G-1 downto 0) := EthPortArrayBigEndian(PORT_G, SIZE_G);
66	
67	   type StateType is (
68	      IDLE_S,
69	      ACC_ARP_TAB_S,
70	      DHCP_HDR_S,
71	      HDR_S,
72	      DHCP_BUFFER_S,
73	      BUFFER_S,
74	      LAST_S);
75	
76	   type RegType is record
77	      linkUp      : slv(SIZE_G-1 downto 0);
78	      tKeep       : slv(15 downto 0);
79	      tData       : slv(127 downto 0);
80	      tLast       : sl;
81	      eofe        : sl;
82	      chPntr      : natural range 0 to SIZE_G-1;
83	      index       : natural range 0 to SIZE_G-1;
84	      arpPos      : Slv8Array(SIZE_G-1 downto 0);
85	      arpTabPos   : Slv8Array(SIZE_G-1 downto 0);
86	      obDhcpSlave : AxiStreamSlaveType;
87	      ibSlaves    : AxiStreamSlaveArray(SIZE_G-1 downto 0);
88	      txMaster    : AxiStreamMasterType;
89	      state       : StateType;
90	   end record RegType;
91	   constant REG_INIT_C : RegType := (
92	      linkUp      => (others => '0'),
93	      tKeep       => (others => '0'),
94	      tData       => (others => '0'),
95	      tLast       => '0',
96	      eofe        => '0',
97	      chPntr      => 0,
98	      index       => 0,
99	      arpPos      => (others => (others => '0')),
100	      arpTabPos   => (others => (others => '0')),
101	      obDhcpSlave => AXI_STREAM_SLAVE_INIT_C,
102	      ibSlaves    => (others => AXI_STREAM_SLAVE_INIT_C),
103	      txMaster    => AXI_STREAM_MASTER_INIT_C,
104	      state       => IDLE_S);
105	
106	   signal r   : RegType := REG_INIT_C;
107	   signal rin : RegType;
108	
109	   signal txMaster : AxiStreamMasterType;
110	   signal txSlave  : AxiStreamSlaveType;
111	
112	   -- attribute dont_touch             : string;
113	   -- attribute dont_touch of r        : signal is "TRUE";
114	
115	begin
116	
117	   comb : process (arpTabFound, arpTabIpAddr, arpTabMacAddr, ibMasters,
118	                   localIp, localMac, obDhcpMaster, r, remoteIp, remoteMac,
119	                   remotePort, rst, txSlave) is
120	      variable v : RegType;
121	   begin
122	      -- Latch the current value
123	      v := r;
124	
125	      -- Reset the flags
126	      v.obDhcpSlave := AXI_STREAM_SLAVE_INIT_C;
127	      v.ibSlaves    := (others => AXI_STREAM_SLAVE_INIT_C);
128	      if (txSlave.tReady = '1') then
129	         v.txMaster.tValid := '0';
130	         v.txMaster.tLast  := '0';
131	         v.txMaster.tUser  := (others => '0');
132	         v.txMaster.tKeep  := (others => '1');
133	      end if;
134	
135	      for i in SIZE_G-1 downto 0 loop
136	         -- Check if link is up
137	         if (localMac /= 0) and         -- Non-zero local MAC address
138	                           (localIp /= 0) and      -- Non-zero local IP address
139	                           (PORT_G(i) /= 0) and    -- Non-zero local UDP port
140	                           (remoteMac(i) /= 0) and  -- Non-zero remote MAC address
141	                           (remoteIp(i) /= 0) and  -- Non-zero remote IP address
142	                           (remotePort(i) /= 0) then  -- Non-zero remote UDP port
143	            -- Link Up
144	            v.linkUp(i) := '1';
145	         else
146	            -- Link down
147	            v.linkUp(i) := '0';
148	         end if;
149	      end loop;
150	
151	      -- State Machine
152	      case r.state is
153	         ----------------------------------------------------------------------
154	         when IDLE_S =>
155	            -- Check for roll over
156	            if (r.index = (SIZE_G-1)) then
157	               -- Reset the counter
158	               v.index := 0;
159	            else
160	               -- Increment the counter
161	               v.index := r.index + 1;
162	            end if;
163	            -- Check for DHCP data and remote MAC is non-zero
164	            if (obDhcpMaster.tValid = '1') and (v.txMaster.tValid = '0') then
165	               -- Check for SOF
166	               if (ssiGetUserSof(EMAC_AXIS_CONFIG_C, obDhcpMaster) = '1') then
167	                  -- Write the first header
168	                  v.txMaster.tValid               := '1';
169	                  v.txMaster.tData(47 downto 0)   := (others => '1');  -- Destination MAC address
170	                  v.txMaster.tData(63 downto 48)  := x"0000";     -- All 0s
171	                  v.txMaster.tData(95 downto 64)  := (others => '0');  -- Source IP address
172	                  v.txMaster.tData(127 downto 96) := (others => '1');  -- Destination IP address
173	                  ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.txMaster, '1');
174	                  -- Next state
175	                  v.state                         := DHCP_HDR_S;
176	               else
177	                  -- Blow off the data
178	                  v.obDhcpSlave.tReady := '1';
179	               end if;
180	            -- Check for data and remote MAC is non-zero
181	            elsif (ibMasters(r.index).tValid = '1') and (v.txMaster.tValid = '0') then
182	               -- Check if need to access ARP Table
183	               if ibMasters(r.index).tDest = x"00" or IS_CLIENT_G = false then
184	                  -- Check if link down and blowing off the data
185	                  if (r.linkUp(r.index) = '0') and TX_FLOW_CTRL_G then
186	                     -- Blow off the data
187	                     v.ibSlaves(r.index).tReady := '1';
188	                  -- Check for SOF
189	                  elsif (ssiGetUserSof(EMAC_AXIS_CONFIG_C, ibMasters(r.index)) = '1') then
190	                     -- Check if link up
191	                     if (r.linkUp(r.index) = '1') then
192	                        -- Latch the index
193	                        v.chPntr                        := r.index;
194	                        -- Write the first header
195	                        v.txMaster.tValid               := '1';
196	                        v.txMaster.tData(47 downto 0)   := remoteMac(r.index);  -- Destination MAC address
197	                        v.txMaster.tData(63 downto 48)  := x"0000";  -- All 0s
198	                        v.txMaster.tData(95 downto 64)  := localIp;  -- Source IP address
199	                        v.txMaster.tData(127 downto 96) := remoteIp(r.index);  -- Destination IP address
200	                        ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.txMaster, '1');
201	                        -- Next state
202	                        v.state                         := HDR_S;
203	                     end if;
204	                  else
205	                     -- Blow off the data
206	                     v.ibSlaves(r.index).tReady := '1';
207	                  end if;
208	               else
209	                  v.chPntr             := r.index;
210	                  v.arpTabPos(r.index) := ibMasters(r.index).tDest;
211	                  v.state              := ACC_ARP_TAB_S;
212	               end if;
213	            end if;
214	         -----------------------------------------------------------------------
215	         when ACC_ARP_TAB_S =>
216	            v.arpTabPos(r.chPntr) := ibMasters(r.chPntr).tDest;
217	            if arpTabFound(r.chPntr) = '0' then
218	               v.linkUp(r.chPntr)          := '0';
219	               -- Blow off the data..
220	               v.ibSlaves(r.chPntr).tReady := '1';
221	               -- ..until the last frame
222	               if (ssiGetUserEofe(EMAC_AXIS_CONFIG_C, ibMasters(r.chPntr)) = '1' or ibMasters(r.chPntr).tLast = '1') then
223	                  v.state := IDLE_S;
224	               end if;
225	            else
226	               -- Check if link down and blowing off the data
227	               if (r.linkUp(r.chPntr) = '0') and TX_FLOW_CTRL_G then
228	                  -- Blow off the data..
229	                  v.ibSlaves(r.chPntr).tReady := '1';
230	                  -- ..until the last frame
231	                  if (ssiGetUserEofe(EMAC_AXIS_CONFIG_C, ibMasters(r.chPntr)) = '1' or ibMasters(r.chPntr).tLast = '1') then
232	                     v.state := IDLE_S;
233	                  end if;
234	               -- Check for SOF
235	               elsif (ssiGetUserSof(EMAC_AXIS_CONFIG_C, ibMasters(r.chPntr)) = '1') then
236	                  -- Check if link up
237	                  if (r.linkUp(r.chPntr) = '1') then
238	                     -- Latch the index
239	                     v.chPntr                        := r.chPntr;
240	                     -- Write the first header
241	                     v.txMaster.tValid               := '1';
242	                     v.txMaster.tData(47 downto 0)   := arpTabMacAddr(r.chPntr);  -- Destination MAC address
243	                     v.txMaster.tData(63 downto 48)  := x"0000";  -- All 0s
244	                     v.txMaster.tData(95 downto 64)  := localIp;  -- Source IP address
245	                     v.txMaster.tData(127 downto 96) := arpTabIpAddr(r.chPntr);  -- Destination IP address
246	                     ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.txMaster, '1');
247	                     -- Next state
248	                     v.state                         := HDR_S;
249	                  end if;
250	               else
251	                  -- Blow off the data..
252	                  v.ibSlaves(r.chPntr).tReady := '1';
253	                  -- ..until the last frame
254	                  if (ssiGetUserEofe(EMAC_AXIS_CONFIG_C, ibMasters(r.chPntr)) = '1' or ibMasters(r.chPntr).tLast = '1') then
255	                     v.state := IDLE_S;
256	                  end if;
257	               end if;
258	            end if;
259	
260	         ------------------------------------------------
261	         -- Notes: Non-Standard IPv4 Pseudo Header Format
262	         ------------------------------------------------
263	         -- tData[0][47:0]   = DST MAC Address
264	         -- tData[0][63:48]  = zeros
265	         -- tData[0][95:64]  = SRC IP Address
266	         -- tData[0][127:96] = DST IP address
267	         -- tData[1][7:0]    = zeros
268	         -- tData[1][15:8]   = Protocol Type = UDP
269	         -- tData[1][31:16]  = IPv4 Pseudo header length
270	         -- tData[1][47:32]  = SRC Port
271	         -- tData[1][63:48]  = DST Port
272	         -- tData[1][79:64]  = UDP Length
273	         -- tData[1][95:80]  = UDP Checksum
274	         -- tData[1][127:96] = UDP Datagram
275	         ------------------------------------------------
276	         ----------------------------------------------------------------------
277	         when DHCP_HDR_S =>
278	            -- Check if ready to move data
279	            if (obDhcpMaster.tValid = '1') and (v.txMaster.tValid = '0') then
280	               -- Accept the data
281	               v.obDhcpSlave.tReady            := '1';
282	               -- Write the Second header
283	               v.txMaster.tValid               := '1';
284	               v.txMaster.tData(7 downto 0)    := x"00";  -- All 0s
285	               v.txMaster.tData(15 downto 8)   := UDP_C;  -- Protocol Type = UDP
286	               v.txMaster.tData(31 downto 16)  := x"0000";  -- IPv4 Pseudo header length = Calculated in EthMac core
287	               v.txMaster.tData(47 downto 32)  := DHCP_CPORT;  -- Source port
288	               v.txMaster.tData(63 downto 48)  := DHCP_SPORT;  -- Destination port
289	               v.txMaster.tData(79 downto 64)  := x"0000";  -- UDP length = Calculated in EthMac core
290	               v.txMaster.tData(95 downto 80)  := x"0000";  -- UDP checksum  = Calculated in EthMac core
291	               v.txMaster.tData(127 downto 96) := obDhcpMaster.tData(31 downto 0);  -- UDP Datagram
292	               v.txMaster.tKeep(11 downto 0)   := x"FFF";
293	               v.txMaster.tKeep(15 downto 12)  := obDhcpMaster.tKeep(3 downto 0);  -- UDP Datagram
294	               -- Track the leftovers
295	               v.tData(95 downto 0)            := obDhcpMaster.tData(127 downto 32);
296	               v.tData(127 downto 96)          := (others => '0');
297	               v.tKeep(11 downto 0)            := obDhcpMaster.tKeep(15 downto 4);
298	               v.tKeep(15 downto 12)           := (others => '0');
299	               v.tLast                         := obDhcpMaster.tLast;
300	               v.eofe                          := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, obDhcpMaster);
301	               -- Check for tLast
302	               if (v.tLast = '1') then
303	                  -- Check the leftover tKeep is not empty
304	                  if (v.tKeep /= 0) then
305	                     -- Next state
306	                     v.state := LAST_S;
307	                  else
308	                     -- Set EOF and EOFE
309	                     v.txMaster.tLast := '1';
310	                     ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
311	                     -- Next state
312	                     v.state          := IDLE_S;
313	                  end if;
314	               else
315	                  -- Next state
316	                  v.state := DHCP_BUFFER_S;
317	               end if;
318	            end if;
319	         ----------------------------------------------------------------------
320	         when HDR_S =>
321	            -- Check if ready to move data
322	            if (ibMasters(r.chPntr).tValid = '1') and (v.txMaster.tValid = '0') then
323	               -- Accept the data
324	               v.ibSlaves(r.chPntr).tReady     := '1';
325	               -- Write the Second header
326	               v.txMaster.tValid               := '1';
327	               v.txMaster.tData(7 downto 0)    := x"00";  -- All 0s
328	               v.txMaster.tData(15 downto 8)   := UDP_C;  -- Protocol Type = UDP
329	               v.txMaster.tData(31 downto 16)  := x"0000";  -- IPv4 Pseudo header length = Calculated in EthMac core
330	               v.txMaster.tData(47 downto 32)  := PORT_C(r.chPntr);  -- Source port
331	               v.txMaster.tData(63 downto 48)  := remotePort(r.chPntr);  -- Destination port
332	               v.txMaster.tData(79 downto 64)  := x"0000";  -- UDP length = Calculated in EthMac core
333	               v.txMaster.tData(95 downto 80)  := x"0000";  -- UDP checksum  = Calculated in EthMac core
334	               v.txMaster.tData(127 downto 96) := ibMasters(r.chPntr).tData(31 downto 0);  -- UDP Datagram
335	               v.txMaster.tKeep(11 downto 0)   := x"FFF";
336	               v.txMaster.tKeep(15 downto 12)  := ibMasters(r.chPntr).tKeep(3 downto 0);  -- UDP Datagram
337	               -- Track the leftovers
338	               v.tData(95 downto 0)            := ibMasters(r.chPntr).tData(127 downto 32);
339	               v.tData(127 downto 96)          := (others => '0');
340	               v.tKeep(11 downto 0)            := ibMasters(r.chPntr).tKeep(15 downto 4);
341	               v.tKeep(15 downto 12)           := (others => '0');
342	               v.tLast                         := ibMasters(r.chPntr).tLast;
343	               v.eofe                          := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, ibMasters(r.chPntr));
344	               -- Check for tLast
345	               if (v.tLast = '1') then
346	                  -- Check the leftover tKeep is not empty
347	                  if (v.tKeep /= 0) then
348	                     -- Next state
349	                     v.state := LAST_S;
350	                  else
351	                     -- Set EOF and EOFE
352	                     v.txMaster.tLast := '1';
353	                     ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
354	                     -- Next state
355	                     v.state          := IDLE_S;
356	                  end if;
357	               else
358	                  -- Next state
359	                  v.state := BUFFER_S;
360	               end if;
361	            end if;
362	         ----------------------------------------------------------------------
363	         when DHCP_BUFFER_S =>
364	            -- Check if ready to move data
365	            if (obDhcpMaster.tValid = '1') and (v.txMaster.tValid = '0') then
366	               -- Accept the data
367	               v.obDhcpSlave.tReady            := '1';
368	               -- Write the Second header
369	               v.txMaster.tValid               := '1';
370	               -- Move the data
371	               v.txMaster.tData(95 downto 0)   := r.tData(95 downto 0);
372	               v.txMaster.tData(127 downto 96) := obDhcpMaster.tData(31 downto 0);
373	               v.txMaster.tKeep(11 downto 0)   := r.tKeep(11 downto 0);
374	               v.txMaster.tKeep(15 downto 12)  := obDhcpMaster.tKeep(3 downto 0);
375	               -- Track the leftovers
376	               v.tData(95 downto 0)            := obDhcpMaster.tData(127 downto 32);
377	               v.tKeep(11 downto 0)            := obDhcpMaster.tKeep(15 downto 4);
378	               v.tLast                         := obDhcpMaster.tLast;
379	               v.eofe                          := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, obDhcpMaster);
380	               -- Check for tLast
381	               if (v.tLast = '1') then
382	                  -- Check the leftover tKeep is not empty
383	                  if (v.tKeep /= 0) then
384	                     -- Next state
385	                     v.state := LAST_S;
386	                  else
387	                     -- Set EOF and EOFE
388	                     v.txMaster.tLast := '1';
389	                     ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
390	                     -- Next state
391	                     v.state          := IDLE_S;
392	                  end if;
393	               end if;
394	            end if;
395	         ----------------------------------------------------------------------
396	         when BUFFER_S =>
397	            -- Check if ready to move data
398	            if (ibMasters(r.chPntr).tValid = '1') and (v.txMaster.tValid = '0') then
399	               -- Accept the data
400	               v.ibSlaves(r.chPntr).tReady     := '1';
401	               -- Write the Second header
402	               v.txMaster.tValid               := '1';
403	               -- Move the data
404	               v.txMaster.tData(95 downto 0)   := r.tData(95 downto 0);
405	               v.txMaster.tData(127 downto 96) := ibMasters(r.chPntr).tData(31 downto 0);
406	               v.txMaster.tKeep(11 downto 0)   := r.tKeep(11 downto 0);
407	               v.txMaster.tKeep(15 downto 12)  := ibMasters(r.chPntr).tKeep(3 downto 0);
408	               -- Track the leftovers
409	               v.tData(95 downto 0)            := ibMasters(r.chPntr).tData(127 downto 32);
410	               v.tKeep(11 downto 0)            := ibMasters(r.chPntr).tKeep(15 downto 4);
411	               v.tLast                         := ibMasters(r.chPntr).tLast;
412	               v.eofe                          := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, ibMasters(r.chPntr));
413	               -- Check for tLast
414	               if (v.tLast = '1') then
415	                  -- Check the leftover tKeep is not empty
416	                  if (v.tKeep /= 0) then
417	                     -- Next state
418	                     v.state := LAST_S;
419	                  else
420	                     -- Set EOF and EOFE
421	                     v.txMaster.tLast := '1';
422	                     ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
423	                     -- Next state
424	                     v.state          := IDLE_S;
425	                  end if;
426	               end if;
427	            end if;
428	         ----------------------------------------------------------------------
429	         when LAST_S =>
430	            -- Check if ready to move data
431	            if (v.txMaster.tValid = '0') then
432	               -- Move the data
433	               v.txMaster.tValid              := '1';
434	               v.txMaster.tData(127 downto 0) := r.tData;
435	               v.txMaster.tKeep(15 downto 0)  := r.tKeep;
436	               v.txMaster.tLast               := '1';
437	               ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, r.eofe);
438	               -- Next state
439	               v.state                        := IDLE_S;
440	            end if;
441	      ----------------------------------------------------------------------
442	      end case;
443	
444	      -- Outputs
445	      ibSlaves    <= v.ibSlaves;
446	      obDhcpSlave <= v.obDhcpSlave;
447	      txMaster    <= r.txMaster;
448	      linkUp      <= r.linkUp;
449	      arpTabPos   <= v.arpTabPos;
450	
451	      -- Reset
452	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
453	         v := REG_INIT_C;
454	      end if;
455	
456	      -- Register the variable for next clock cycle
457	      rin <= v;
458	
459	   end process comb;
460	
461	   seq : process (clk, rst) is
462	   begin
463	      if (RST_ASYNC_G and rst = RST_POLARITY_G) then
464	         r <= REG_INIT_C after TPD_G;
465	      elsif rising_edge(clk) then
466	         r <= rin after TPD_G;
467	      end if;
468	   end process seq;
469	
470	   U_TxPipeline : entity surf.AxiStreamPipeline
471	      generic map (
472	         TPD_G          => TPD_G,
473	         RST_POLARITY_G => RST_POLARITY_G,
474	         RST_ASYNC_G    => RST_ASYNC_G,
475	         PIPE_STAGES_G  => 1)
476	      port map (
477	         axisClk     => clk,
478	         axisRst     => rst,
479	         sAxisMaster => txMaster,
480	         sAxisSlave  => txSlave,
481	         mAxisMaster => obUdpMaster,
482	         mAxisSlave  => obUdpSlave);
483	
484	end rtl;
485

