14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiStreamPkg.all;
23	use surf.SsiPkg.all;
24	use surf.EthMacPkg.all;
25	
26	entity UdpEngineDhcp is
27	   generic (
28	      TPD_G          : time     := 1 ns;
29	      RST_POLARITY_G : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
30	      RST_ASYNC_G    : boolean  := false;
31	      -- UDP ARP/DHCP Generics
32	      CLK_FREQ_G     : real     := 156.25E+06;  -- In units of Hz
33	      COMM_TIMEOUT_G : positive := 30;
34	      -- RAM/FIFO synthesis mode
35	      SYNTH_MODE_G   : string   := "inferred");
36	   port (
37	      -- Local Configurations
38	      localMac     : in  slv(47 downto 0);      --  big-Endian configuration
39	      localIp      : in  slv(31 downto 0);      --  big-Endian configuration
40	      dhcpIp       : out slv(31 downto 0);      --  big-Endian configuration
41	      -- Interface to DHCP Engine
42	      ibDhcpMaster : in  AxiStreamMasterType;
43	      ibDhcpSlave  : out AxiStreamSlaveType;
44	      obDhcpMaster : out AxiStreamMasterType;
45	      obDhcpSlave  : in  AxiStreamSlaveType;
46	      -- Clock and Reset
47	      clk          : in  sl;
48	      rst          : in  sl);
49	end UdpEngineDhcp;
50	
51	architecture rtl of UdpEngineDhcp is
52	
53	   constant DHCP_CONFIG_C  : AxiStreamConfigType := ssiAxiStreamConfig(4);
54	   constant TIMER_1_SEC_C  : natural             := getTimeRatio(CLK_FREQ_G, 1.0);
55	   constant CLIENT_HDR_C   : slv(31 downto 0)    := x"00060101";  -- 0x01010600
56	   constant SERVER_HDR_C   : slv(31 downto 0)    := x"00060102";  -- 0x02010600
57	   constant MAGIC_COOKIE_C : slv(31 downto 0)    := x"63538263";  -- 0x63825363
58	   constant COMM_TIMEOUT_C : positive            := ite((COMM_TIMEOUT_G > 3), COMM_TIMEOUT_G, 3);
59	
60	   type StateType is (
61	      IDLE_S,
62	      REQ_S,
63	      BOOTP_S,
64	      DHCP_S,
65	      VERIFY_S);
66	
67	   type DecodeType is (
68	      CODE_S,
69	      LEN_S,
70	      DATA_S);
71	
72	   type RegType is record
73	      localMac   : slv(47 downto 0);
74	      heartbeat  : sl;
75	      cnt        : natural range 0 to 127;
76	      timer      : natural range 0 to (TIMER_1_SEC_C-1);
77	      commCnt    : natural range 0 to COMM_TIMEOUT_C;
78	      renewCnt   : slv(30 downto 0);
79	      leaseCnt   : slv(31 downto 0);
80	      leaseTime  : slv(31 downto 0);
81	      remoteMac  : slv(47 downto 0);
82	      remoteIp   : slv(31 downto 0);
83	      dhcpIp     : slv(31 downto 0);
84	      dhcpReq    : sl;
85	      xid        : slv(31 downto 0);
86	      yiaddr     : slv(31 downto 0);
87	      siaddr     : slv(31 downto 0);
88	      yiaddrTemp : slv(31 downto 0);
89	      siaddrTemp : slv(31 downto 0);
90	      index      : natural range 0 to 3;
91	      valid      : slv(4 downto 0);
92	      opCode     : slv(7 downto 0);
93	      len        : slv(7 downto 0);
94	      msgType    : slv(7 downto 0);
95	      rxSlave    : AxiStreamSlaveType;
96	      txMaster   : AxiStreamMasterType;
97	      decode     : DecodeType;
98	      state      : StateType;
99	   end record RegType;
100	   constant REG_INIT_C : RegType := (
101	      localMac   => (others => '0'),
102	      heartbeat  => '0',
103	      cnt        => 0,
104	      timer      => 0,
105	      commCnt    => 3,                  -- Default to 3 seconds after bootup
106	      renewCnt   => (others => '0'),
107	      leaseCnt   => (others => '0'),
108	      leaseTime  => (others => '0'),
109	      remoteMac  => (others => '1'),    -- Broadcast MAC Address
110	      remoteIp   => (others => '1'),    -- Broadcast IP Address
111	      dhcpIP     => (others => '0'),
112	      dhcpReq    => '0',
113	      xid        => (others => '0'),
114	      yiaddr     => (others => '0'),
115	      siaddr     => (others => '0'),
116	      yiaddrTemp => (others => '0'),
117	      siaddrTemp => (others => '0'),
118	      index      => 0,
119	      valid      => (others => '0'),
120	      opCode     => (others => '0'),
121	      len        => (others => '0'),
122	      msgType    => (others => '0'),
123	      rxSlave    => AXI_STREAM_SLAVE_INIT_C,
124	      txMaster   => AXI_STREAM_MASTER_INIT_C,
125	      decode     => CODE_S,
126	      state      => IDLE_S);
127	
128	   signal r   : RegType := REG_INIT_C;
129	   signal rin : RegType;
130	
131	   signal rxMaster : AxiStreamMasterType;
132	   signal rxSlave  : AxiStreamSlaveType;
133	   signal txMaster : AxiStreamMasterType;
134	   signal txSlave  : AxiStreamSlaveType;
135	
136	   -- attribute dont_touch             : string;
137	   -- attribute dont_touch of r        : signal is "TRUE";
138	   -- attribute dont_touch of rxMaster : signal is "TRUE";
139	   -- attribute dont_touch of rxSlave  : signal is "TRUE";
140	   -- attribute dont_touch of txMaster : signal is "TRUE";
141	   -- attribute dont_touch of txSlave  : signal is "TRUE";
142	
143	begin
144	
145	   FIFO_RX : entity surf.AxiStreamFifoV2
146	      generic map (
147	         -- General Configurations
148	         TPD_G               => TPD_G,
149	         RST_POLARITY_G      => RST_POLARITY_G,
150	         RST_ASYNC_G         => RST_ASYNC_G,
151	         INT_PIPE_STAGES_G   => 0,
152	         PIPE_STAGES_G       => 0,
153	         SLAVE_READY_EN_G    => true,
154	         VALID_THOLD_G       => 1,
155	         -- FIFO configurations
156	         SYNTH_MODE_G        => SYNTH_MODE_G,
157	         MEMORY_TYPE_G       => "distributed",
158	         GEN_SYNC_FIFO_G     => true,
159	         CASCADE_SIZE_G      => 1,
160	         FIFO_ADDR_WIDTH_G   => 4,
161	         -- AXI Stream Port Configurations
162	         SLAVE_AXI_CONFIG_G  => EMAC_AXIS_CONFIG_C,
163	         MASTER_AXI_CONFIG_G => DHCP_CONFIG_C)
164	      port map (
165	         -- Slave Port
166	         sAxisClk    => clk,
167	         sAxisRst    => rst,
168	         sAxisMaster => ibDhcpMaster,
169	         sAxisSlave  => ibDhcpSlave,
170	         -- Master Port
171	         mAxisClk    => clk,
172	         mAxisRst    => rst,
173	         mAxisMaster => rxMaster,
174	         mAxisSlave  => rxSlave);
175	
176	   comb : process (localIp, localMac, r, rst, rxMaster, txSlave) is
177	      variable v     : RegType;
178	      variable tData : slv(7 downto 0);
179	      variable tKeep : slv(15 downto 0);
180	   begin
181	      -- Latch the current value
182	      v := r;
183	
184	      -- Reset the flags
185	      v.heartbeat := '0';
186	      v.rxSlave   := AXI_STREAM_SLAVE_INIT_C;
187	      if txSlave.tReady = '1' then
188	         v.txMaster.tValid := '0';
189	         v.txMaster.tLast  := '0';
190	         v.txMaster.tUser  := (others => '0');
191	      end if;
192	
193	      -- Check 1 second heartbeat timeout
194	      if r.timer = (TIMER_1_SEC_C-1) then
195	         -- Reset the counter
196	         v.timer     := 0;
197	         -- Set the timeout flag
198	         v.heartbeat := '1';
199	      else
200	         -- Increment the counter
201	         v.timer := r.timer + 1;
202	      end if;
203	
204	      -- Check for heart beat
205	      if (r.heartbeat = '1') then
206	         -- Check Communication timer
207	         if (r.commCnt /= 0) then
208	            -- Decrement the counter
209	            v.commCnt := r.commCnt - 1;
210	         end if;
211	         -- Check DHCP renewal timer
212	         if (r.renewCnt /= 0) then
213	            -- Decrement the counter
214	            v.renewCnt := r.renewCnt - 1;
215	         end if;
216	         -- Check DHCP lease timer
217	         if (r.leaseCnt /= 0) then
218	            -- Decrement the counter
219	            v.leaseCnt := r.leaseCnt - 1;
220	            -- Check for DHCP lease expire event
221	            if (r.leaseCnt = 1) then
222	               -- Set the flag
223	               v.dhcpReq   := '0';
224	               -- Reset the renewal counter
225	               v.renewCnt  := (others => '0');
226	               -- Broadcast the MAC/IP addresses
227	               v.remoteMac := (others => '1');
228	               v.remoteIp  := (others => '1');
229	            end if;
230	         else
231	            -- Set DHCP IP address to local value
232	            v.dhcpIP := localIp;
233	         end if;
234	      end if;
235	
236	      -- Update the variables
237	      tData := rxMaster.tData((8*r.index)+7 downto (8*r.index));
238	      tKeep := x"000" & rxMaster.tKeep(3 downto 0);
239	
240	      -- State Machine
241	      case r.state is
242	         ----------------------------------------------------------------------
243	         when IDLE_S =>
244	            -- Check for inbound data
245	            if (rxMaster.tValid = '1') then
246	               -- Accept the data
247	               v.rxSlave.tReady := '1';
248	               -- Check for SOF with no EOF
249	               if (ssiGetUserSof(DHCP_CONFIG_C, rxMaster) = '1') and (rxMaster.tLast = '0') then
250	                  -- Check for valid DHCP server OP/HTYPE/HLEN (ignore HOPS field)
251	                  if rxMaster.tData(23 downto 0) = SERVER_HDR_C(23 downto 0) then
252	                     -- Preset the counter
253	                     v.cnt   := 1;
254	                     -- Next state
255	                     v.state := BOOTP_S;
256	                  end if;
257	               end if;
258	            else
259	               -- Check DHCP renewal timer
260	               if (r.renewCnt = 0) then
261	                  -- Check for communication timeout
262	                  if r.commCnt = 0 then
263	                     -- Reset the counter
264	                     v.cnt   := 0;
265	                     -- Increment the counter
266	                     v.xid   := r.xid + 1;
267	                     -- Next state
268	                     v.state := REQ_S;
269	                  end if;
270	               end if;
271	            end if;
272	         ----------------------------------------------------------------------
273	         when REQ_S =>
274	            -- Check if ready to move data
275	            if v.txMaster.tValid = '0' then
276	               -- Set the default value
277	               v.txMaster.tValid             := '1';
278	               v.txMaster.tData(31 downto 0) := (others => '0');
279	               -- Increment the counter
280	               v.cnt                         := r.cnt + 1;
281	               -- Check the counter
282	               case r.cnt is
283	                  -- OP/HTYPE/HLEN/HOPS
284	                  when 0 =>
285	                     v.txMaster.tData(31 downto 0) := CLIENT_HDR_C;
286	                     v.txMaster.tKeep(15 downto 0) := x"000F";
287	                     ssiSetUserSof(DHCP_CONFIG_C, v.txMaster, '1');
288	                  -- XID
289	                  when 1 =>
290	                     -- Save the XID as big Endian
291	                     v.txMaster.tData(31 downto 24) := r.xid(7 downto 0);
292	                     v.txMaster.tData(23 downto 16) := r.xid(15 downto 8);
293	                     v.txMaster.tData(15 downto 8)  := r.xid(23 downto 16);
294	                     v.txMaster.tData(7 downto 0)   := r.xid(31 downto 24);
295	                  -- SECS/FLAGS
296	                  when 2 =>
297	                     v.txMaster.tData(31 downto 0) := x"00080000";
298	                  -- SIADDR
299	                  when 5 =>
300	                     -- Check for DHCP request
301	                     if r.dhcpReq = '1' then
302	                        v.txMaster.tData(31 downto 0) := r.siaddr;
303	                     end if;
304	                  -- CHADDR[31:0]
305	                  when 7 =>
306	                     v.txMaster.tData(31 downto 0) := r.localMac(31 downto 0);
307	                  -- CHADDR[47:32]
308	                  when 8 =>
309	                     v.txMaster.tData(15 downto 0) := r.localMac(47 downto 32);
310	                  -- Magic cookie
311	                  when 59 =>
312	                     v.txMaster.tData(31 downto 0) := MAGIC_COOKIE_C;
313	                  -- DHCP Discover
314	                  when 60 =>
315	                     -- Check for DHCP Discover
316	                     if r.dhcpReq = '0' then
317	                        v.txMaster.tData(7 downto 0)   := toSlv(53, 8);  -- code = DHCP Message Type
318	                        v.txMaster.tData(15 downto 8)  := x"01";  -- len = 1 byte
319	                        v.txMaster.tData(23 downto 16) := x"01";  -- DHCP Discover = 0x1
320	                        v.txMaster.tData(31 downto 24) := x"FF";  -- Endmark
321	                        v.txMaster.tLast               := '1';
322	                        -- Start the communication timer
323	                        v.commCnt                      := COMM_TIMEOUT_C;
324	                        -- Reset the counter
325	                        v.cnt                          := 0;
326	                        -- Next state
327	                        v.state                        := IDLE_S;
328	                     else
329	                        v.txMaster.tData(7 downto 0)   := toSlv(53, 8);  -- code = DHCP Message Type
330	                        v.txMaster.tData(15 downto 8)  := x"01";  -- len = 1 byte
331	                        v.txMaster.tData(23 downto 16) := x"03";  -- DHCP request = 0x3
332	                     end if;
333	                  -- Requested IP address[15:0]
334	                  when 61 =>
335	                     v.txMaster.tData(7 downto 0)   := toSlv(50, 8);  -- code = Requested IP address
336	                     v.txMaster.tData(15 downto 8)  := x"04";  -- len = 4 byte
337	                     v.txMaster.tData(31 downto 16) := r.yiaddr(15 downto 0);  -- YIADDR[15:0]
338	                  -- Requested IP address[32:16]
339	                  when 62 =>
340	                     v.txMaster.tData(15 downto 0) := r.yiaddr(31 downto 16);  -- YIADDR[31:16]
341	                  -- Server Identifier[15:0]
342	                  when 63 =>
343	                     v.txMaster.tData(7 downto 0)   := toSlv(54, 8);  -- code = Server Identifier
344	                     v.txMaster.tData(15 downto 8)  := x"04";  -- len = 4 byte
345	                     v.txMaster.tData(31 downto 16) := r.siaddr(15 downto 0);  -- SIADDR[15:0]
346	                  -- Server Identifier[32:16]
347	                  when 64 =>
348	                     v.txMaster.tData(15 downto 0) := r.siaddr(31 downto 16);  -- SIADDR[31:16]
349	                  when 65 =>
350	                     v.txMaster.tData(7 downto 0)  := x"FF";   -- Endmark
351	                     v.txMaster.tKeep(15 downto 0) := x"0001";
352	                     v.txMaster.tLast              := '1';
353	                     -- Start the communication timer
354	                     v.commCnt                     := COMM_TIMEOUT_C;
355	                     -- Reset the counter
356	                     v.cnt                         := 0;
357	                     -- Next state
358	                     v.state                       := IDLE_S;
359	                  when others =>
360	                     null;
361	               end case;
362	            end if;
363	         ----------------------------------------------------------------------
364	         when BOOTP_S =>
365	            -- Check for request data
366	            if (rxMaster.tValid = '1') then
367	               -- Accept the data
368	               v.rxSlave.tReady := '1';
369	               -- Increment the counter
370	               v.cnt            := r.cnt + 1;
371	               -- Check the counter
372	               case r.cnt is
373	                  -- XID
374	                  when 1 =>
375	                     -- Check if XID doesn't match
376	                     if (rxMaster.tData(31 downto 24) /= r.xid(7 downto 0))
377	                        or (rxMaster.tData(23 downto 16) /= r.xid(15 downto 8))
378	                        or (rxMaster.tData(15 downto 8) /= r.xid(23 downto 16))
379	                        or (rxMaster.tData(7 downto 0) /= r.xid(31 downto 24)) then
380	                        -- Next state
381	                        v.state := IDLE_S;
382	                     end if;
383	                  -- YIADDR
384	                  when 4 =>
385	                     v.yiaddrTemp := rxMaster.tData(31 downto 0);
386	                  -- SIADDR
387	                  when 5 =>
388	                     v.siaddrTemp := rxMaster.tData(31 downto 0);
389	                  -- CHADDR[31:0]
390	                  when 7 =>
391	                     -- Check if CHADDR[31:0] doesn't match
392	                     if rxMaster.tData(31 downto 0) /= r.localMac(31 downto 0) then
393	                        -- Next state
394	                        v.state := IDLE_S;
395	                     end if;
396	                  -- CHADDR[47:32]
397	                  when 8 =>
398	                     -- Check if CHADDR[47:32] doesn't match
399	                     if rxMaster.tData(15 downto 0) /= r.localMac(47 downto 32) then
400	                        -- Next state
401	                        v.state := IDLE_S;
402	                     end if;
403	                  -- Magic cookie
404	                  when 59 =>
405	                     -- Check if Magic cookie doesn't match
406	                     if rxMaster.tData(31 downto 0) /= MAGIC_COOKIE_C then
407	                        -- Next state
408	                        v.state := IDLE_S;
409	                     else
410	                        -- Reset data fields
411	                        v.valid  := (others => '0');
412	                        v.index  := 0;
413	                        v.decode := CODE_S;
414	                        -- Next state
415	                        v.state  := DHCP_S;
416	                     end if;
417	                  when others =>
418	                     null;
419	               end case;
420	               -- Check for early packet termination
421	               if (rxMaster.tLast = '1') then
422	                  -- Next state
423	                  v.state := IDLE_S;
424	               end if;
425	            end if;
426	         ----------------------------------------------------------------------
427	         when DHCP_S =>
428	            -- Check for request data
429	            if (rxMaster.tValid = '1') then
430	               -- Decode State Machine
431	               case r.decode is
432	                  ----------------------------------------------------------------
433	                  when CODE_S =>
434	                     -- Save the OP-code value
435	                     v.opCode := tData;
436	                     -- Check for not "PAD" and not "End" OP-code
437	                     if (tData /= 0) and (tData /= 255) then
438	                        -- Next state
439	                        v.decode := LEN_S;
440	                     end if;
441	                  ----------------------------------------------------------------
442	                  when LEN_S =>
443	                     -- Save the length
444	                     v.len := tData;
445	                     -- Check for non-zero length
446	                     if tData /= 0 then
447	                        -- Next state
448	                        v.decode := DATA_S;
449	                     else               -- Error detected
450	                        -- Next state
451	                        v.state := IDLE_S;
452	                     end if;
453	                  ----------------------------------------------------------------
454	                  when DATA_S =>
455	                     -- Decrement the counter
456	                     v.len := r.len - 1;
457	                     -- Check for last byte
458	                     if (r.len = 1) then
459	                        -- Next state
460	                        v.decode := CODE_S;
461	                     end if;
462	                     -- Check the Code
463	                     if (r.opCode = 53) then  -- Note: Assuming zero padding
464	                        -- Check for DHCP Message Type
465	
466	                        if (r.len = 1) then
467	                           -- Set the flag
468	                           v.valid(0) := '1';
469	                           -- Save the message
470	                           v.msgType  := tData;
471	                        end if;
472	                     -- Check for IP address Lease Time
473	                     elsif (r.opcode = 51) then
474	                        if r.len = 4 then
475	                           -- Set the flag
476	                           v.valid(1)                := '1';
477	                           v.leaseTime(31 downto 24) := tData;
478	                        elsif r.len = 3 then
479	                           -- Set the flag
480	                           v.valid(2)                := '1';
481	                           v.leaseTime(23 downto 16) := tData;
482	                        elsif r.len = 2 then
483	                           -- Set the flag
484	                           v.valid(3)               := '1';
485	                           v.leaseTime(15 downto 8) := tData;
486	                        elsif r.len = 1 then
487	                           -- Set the flag
488	                           v.valid(4)              := '1';
489	                           v.leaseTime(7 downto 0) := tData;
490	                        end if;
491	                     end if;
492	
493	               ----------------------------------------------------------------
494	               end case;
495	               -- Check the counter
496	               if r.index = 3 then
497	                  -- Reset the counter
498	                  v.index          := 0;
499	                  -- Accept the data
500	                  v.rxSlave.tReady := '1';
501	               else
502	                  v.index := r.index + 1;
503	               end if;
504	               -- Check for last transfer
505	               if (rxMaster.tLast = '1') and (getTKeep(tKeep, DHCP_CONFIG_C) = (r.index+1)) then
506	                  -- Check for no EOFE
507	                  if ssiGetUserEofe(DHCP_CONFIG_C, rxMaster) = '0' then
508	                     -- Next state
509	                     v.state := VERIFY_S;
510	                  else
511	                     -- Next state
512	                     v.state := IDLE_S;
513	                  end if;
514	               end if;
515	            end if;
516	         ----------------------------------------------------------------------
517	         when VERIFY_S =>
518	            -- Check if armed
519	            if uAnd(r.valid) = '1' then
520	               -- Save the values
521	               v.yiaddr := r.yiaddrTemp;
522	               v.siaddr := r.siaddrTemp;
523	               -- Check for "DHCP Discover" request and "DHCP Offer" reply
524	               if (r.dhcpReq = '0') and (r.msgType = 2) then
525	                  -- Set the flag
526	                  v.dhcpReq := '1';
527	                  -- Reset counter to immediately start the "DHCP request"
528	                  v.commCnt := 0;
529	               -- Check for "DHCP request" request and "DHCP ACK" reply
530	               elsif (r.dhcpReq = '1') and (r.msgType = 5) then
531	                  -- Set the DHCP address
532	                  v.dhcpIp   := r.yiaddrTemp;
533	                  -- Clients begin to attempt to renew their leases
534	                  -- once half the lease interval has expired.
535	                  v.renewCnt := r.leaseTime(31 downto 1);
536	                  v.leaseCnt := r.leaseTime;
537	               end if;
538	            end if;
539	            -- Next state
540	            v.state := IDLE_S;
541	      ----------------------------------------------------------------------
542	      end case;
543	
544	      -- Keep delayed copy of the local MAC
545	      v.localMac := localMac;
546	
547	      -- Combinatorial outputs before the reset
548	      rxSlave <= v.rxSlave;
549	
550	      -- Reset
551	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) or (r.localMac /= v.localMac) or (r.localMac = 0) then
552	         -- Reset the DHCP FSM
553	         v                := REG_INIT_C;
554	         -- Don't touch the delayed copy of local MAC
555	         v.localMac       := localMac;
556	         -- Prevent locking up the ETH stack
557	         v.rxSlave.tReady := '1';
558	      end if;
559	
560	      -- Register the variable for next clock cycle
561	      rin <= v;
562	
563	      -- Registered Outputs
564	      txMaster <= r.txMaster;
565	      dhcpIp   <= r.dhcpIp;
566	
567	   end process comb;
568	
569	   seq : process (clk, rst) is
570	   begin
571	      if (RST_ASYNC_G and rst = RST_POLARITY_G) then
572	         r <= REG_INIT_C after TPD_G;
573	      elsif rising_edge(clk) then
574	         r <= rin after TPD_G;
575	      end if;
576	   end process seq;
577	
578	   FIFO_TX : entity surf.AxiStreamFifoV2
579	      generic map (
580	         -- General Configurations
581	         TPD_G               => TPD_G,
582	         RST_POLARITY_G      => RST_POLARITY_G,
583	         RST_ASYNC_G         => RST_ASYNC_G,
584	         INT_PIPE_STAGES_G   => 0,
585	         PIPE_STAGES_G       => 0,
586	         SLAVE_READY_EN_G    => true,
587	         VALID_THOLD_G       => 1,
588	         -- FIFO configurations
589	         SYNTH_MODE_G        => SYNTH_MODE_G,
590	         MEMORY_TYPE_G       => "distributed",
591	         GEN_SYNC_FIFO_G     => true,
592	         CASCADE_SIZE_G      => 1,
593	         FIFO_ADDR_WIDTH_G   => 4,
594	         -- AXI Stream Port Configurations
595	         SLAVE_AXI_CONFIG_G  => DHCP_CONFIG_C,
596	         MASTER_AXI_CONFIG_G => EMAC_AXIS_CONFIG_C)
597	      port map (
598	         -- Slave Port
599	         sAxisClk    => clk,
600	         sAxisRst    => rst,
601	         sAxisMaster => txMaster,
602	         sAxisSlave  => txSlave,
603	         -- Master Port
604	         mAxisClk    => clk,
605	         mAxisRst    => rst,
606	         mAxisMaster => obDhcpMaster,
607	         mAxisSlave  => obDhcpSlave);
608	
609	end rtl;
610

