16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_unsigned.all;
19	use ieee.std_logic_arith.all;
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiStreamPkg.all;
24	use surf.SsiPkg.all;
25	use surf.EthMacPkg.all;
26	
27	entity UdpEngineRx is
28	   generic (
29	      TPD_G          : time          := 1 ns;
30	      RST_POLARITY_G : sl            := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
31	      RST_ASYNC_G    : boolean       := false;
32	      -- UDP General Generic
33	      DHCP_G         : boolean       := false;
34	      IGMP_G         : boolean       := false;
35	      IGMP_GRP_SIZE  : positive      := 1;
36	      -- UDP Server Generics
37	      SERVER_EN_G    : boolean       := true;
38	      SERVER_SIZE_G  : positive      := 1;
39	      SERVER_PORTS_G : PositiveArray := (0 => 8192);
40	      -- UDP Client Generics
41	      CLIENT_EN_G    : boolean       := true;
42	      CLIENT_SIZE_G  : positive      := 1;
43	      CLIENT_PORTS_G : PositiveArray := (0 => 8193));
44	   port (
45	      -- Local Configurations
46	      localIp              : in  slv(31 downto 0);  --  big-Endian configuration
47	      broadcastIp          : in  slv(31 downto 0);  --  big-Endian configuration
48	      igmpIp               : in  Slv32Array(IGMP_GRP_SIZE-1 downto 0);  --  big-Endian configuration
49	      -- Interface to IPV4 Engine
50	      ibUdpMaster          : in  AxiStreamMasterType;
51	      ibUdpSlave           : out AxiStreamSlaveType;
52	      -- Interface to UDP Server engine(s)
53	      serverRemotePort     : out Slv16Array(SERVER_SIZE_G-1 downto 0);
54	      serverRemoteIp       : out Slv32Array(SERVER_SIZE_G-1 downto 0);
55	      serverRemoteMac      : out Slv48Array(SERVER_SIZE_G-1 downto 0);
56	      obServerMasters      : out AxiStreamMasterArray(SERVER_SIZE_G-1 downto 0);
57	      obServerSlaves       : in  AxiStreamSlaveArray(SERVER_SIZE_G-1 downto 0);
58	      -- Interface to UDP Client engine(s)
59	      clientRemoteDetValid : out slv(CLIENT_SIZE_G-1 downto 0);
60	      clientRemoteDetIp    : out Slv32Array(CLIENT_SIZE_G-1 downto 0);
61	      obClientMasters      : out AxiStreamMasterArray(CLIENT_SIZE_G-1 downto 0);
62	      obClientSlaves       : in  AxiStreamSlaveArray(CLIENT_SIZE_G-1 downto 0);
63	      -- Interface to DHCP Engine
64	      ibDhcpMaster         : out AxiStreamMasterType;
65	      ibDhcpSlave          : in  AxiStreamSlaveType;
66	      -- Clock and Reset
67	      clk                  : in  sl;
68	      rst                  : in  sl);
69	end UdpEngineRx;
70	
71	architecture rtl of UdpEngineRx is
72	
73	   constant SERVER_PORTS_C : Slv16Array(SERVER_SIZE_G-1 downto 0) := EthPortArrayBigEndian(SERVER_PORTS_G, SERVER_SIZE_G);
74	   constant CLIENT_PORTS_C : Slv16Array(CLIENT_SIZE_G-1 downto 0) := EthPortArrayBigEndian(CLIENT_PORTS_G, CLIENT_SIZE_G);
75	
76	   type RouteType is (
77	      NULL_S,
78	      SERVER_S,
79	      CLIENT_S,
80	      DHCP_S);
81	
82	   type StateType is (
83	      IDLE_S,
84	      CHECK_PORT_S,
85	      MOVE_S,
86	      LAST_S);
87	
88	   type RegType is record
89	      tDestServer          : slv(7 downto 0);
90	      tDestClient          : slv(7 downto 0);
91	      serverRemotePort     : Slv16Array(SERVER_SIZE_G-1 downto 0);
92	      serverRemoteIp       : Slv32Array(SERVER_SIZE_G-1 downto 0);
93	      serverRemoteMac      : Slv48Array(SERVER_SIZE_G-1 downto 0);
94	      clientRemoteDetValid : slv(CLIENT_SIZE_G-1 downto 0);
95	      clientRemoteDetIp    : Slv32Array(CLIENT_SIZE_G-1 downto 0);
96	      byteCnt              : slv(15 downto 0);
97	      tData                : slv(127 downto 0);
98	      sof                  : sl;
99	      localHost            : sl;
100	      route                : RouteType;
101	      rxSlave              : AxiStreamSlaveType;
102	      dhcpMaster           : AxiStreamMasterType;
103	      serverMaster         : AxiStreamMasterType;
104	      clientMaster         : AxiStreamMasterType;
105	      state                : StateType;
106	   end record RegType;
107	   constant REG_INIT_C : RegType := (
108	      tDestServer          => (others => '0'),
109	      tDestClient          => (others => '0'),
110	      serverRemotePort     => (others => (others => '0')),
111	      serverRemoteIp       => (others => (others => '0')),
112	      serverRemoteMac      => (others => (others => '0')),
113	      clientRemoteDetValid => (others => '0'),
114	      clientRemoteDetIp    => (others => (others => '0')),
115	      byteCnt              => (others => '0'),
116	      tData                => (others => '0'),
117	      sof                  => '1',
118	      localHost            => '0',
119	      route                => NULL_S,
120	      rxSlave              => AXI_STREAM_SLAVE_INIT_C,
121	      dhcpMaster           => AXI_STREAM_MASTER_INIT_C,
122	      serverMaster         => AXI_STREAM_MASTER_INIT_C,
123	      clientMaster         => AXI_STREAM_MASTER_INIT_C,
124	      state                => IDLE_S);
125	
126	   signal r   : RegType := REG_INIT_C;
127	   signal rin : RegType;
128	
129	   signal rxMaster : AxiStreamMasterType;
130	   signal rxSlave  : AxiStreamSlaveType;
131	
132	   signal serverSlave : AxiStreamSlaveType;
133	   signal clientSlave : AxiStreamSlaveType;
134	   signal dhcpSlave   : AxiStreamSlaveType;
135	
136	   -- attribute dont_touch      : string;
137	   -- attribute dont_touch of r : signal is "TRUE";
138	
139	begin
140	
141	   U_RxPipeline : entity surf.AxiStreamPipeline
142	      generic map (
143	         TPD_G          => TPD_G,
144	         RST_POLARITY_G => RST_POLARITY_G,
145	         RST_ASYNC_G    => RST_ASYNC_G,
146	         PIPE_STAGES_G  => 0)
147	      port map (
148	         axisClk     => clk,
149	         axisRst     => rst,
150	         sAxisMaster => ibUdpMaster,
151	         sAxisSlave  => ibUdpSlave,
152	         mAxisMaster => rxMaster,
153	         mAxisSlave  => rxSlave);
154	
155	   comb : process (broadcastIp, clientSlave, dhcpSlave, igmpIp, localIp, r,
156	                   rst, rxMaster, serverSlave) is
157	      variable v            : RegType;
158	      variable multiCastDet : boolean;
159	   begin
160	      -- Latch the current value
161	      v := r;
162	
163	      -- Reset the flags
164	      v.clientRemoteDetValid := (others => '0');
165	      v.rxSlave              := AXI_STREAM_SLAVE_INIT_C;
166	      if serverSlave.tReady = '1' then
167	         v.serverMaster.tValid := '0';
168	         v.serverMaster.tLast  := '0';
169	         v.serverMaster.tUser  := (others => '0');
170	         v.serverMaster.tKeep  := (others => '1');
171	      end if;
172	      if clientSlave.tReady = '1' then
173	         v.clientMaster.tValid := '0';
174	         v.clientMaster.tLast  := '0';
175	         v.clientMaster.tUser  := (others => '0');
176	         v.clientMaster.tKeep  := (others => '1');
177	      end if;
178	      if (dhcpSlave.tReady) = '1' then
179	         v.dhcpMaster.tValid := '0';
180	         v.dhcpMaster.tLast  := '0';
181	         v.dhcpMaster.tUser  := (others => '0');
182	         v.dhcpMaster.tKeep  := (others => '1');
183	      end if;
184	
185	      -- Check for IGMP multi-cast
186	      multiCastDet := false;
187	      if IGMP_G then
188	         for i in IGMP_GRP_SIZE-1 downto 0 loop
189	            if r.tData(127 downto 96) = igmpIp(i) then
190	               multiCastDet := true;
191	            end if;
192	         end loop;
193	      end if;
194	
195	      -- State Machine
196	      case r.state is
197	         ----------------------------------------------------------------------
198	         when IDLE_S =>
199	            -- Check for data
200	            if (rxMaster.tValid = '1') then
201	               -- Accept the data
202	               v.rxSlave.tReady := '1';
203	               -- Check for SOF with no EOF
204	               if (ssiGetUserSof(EMAC_AXIS_CONFIG_C, rxMaster) = '1') and (rxMaster.tLast = '0') then
205	                  -- Latch the first header
206	                  v.tData := rxMaster.tData(127 downto 0);
207	                  -- Next state
208	                  v.state := CHECK_PORT_S;
209	               end if;
210	            end if;
211	         ----------------------------------------------------------------------
212	         when CHECK_PORT_S =>
213	            -- Check for data
214	            if (rxMaster.tValid = '1') then
215	               -- Accept the data
216	               v.rxSlave.tReady := '1';
217	               -- Set default route type
218	               v.route          := NULL_S;
219	               ------------------------------------------------
220	               -- Notes: Non-Standard IPv4 Pseudo Header Format
221	               ------------------------------------------------
222	               -- tData[0][47:0]   = Remote MAC Address
223	               -- tData[0][63:48]  = zeros
224	               -- tData[0][95:64]  = Remote IP Address
225	               -- tData[0][127:96] = Local IP address
226	               -- tData[1][7:0]    = zeros
227	               -- tData[1][15:8]   = Protocol Type = UDP
228	               -- tData[1][31:16]  = IPv4 Pseudo header length
229	               -- tData[1][47:32]  = Remote Port
230	               -- tData[1][63:48]  = Local Port
231	               -- tData[1][79:64]  = UDP Length
232	               -- tData[1][95:80]  = UDP Checksum
233	               -- tData[1][127:96] = UDP Datagram
234	               ------------------------------------------------
235	               -- Check the local IP address or broadcast IP
236	               if (r.tData(127 downto 96) = localIp) or (r.tData(127 downto 96) = broadcastIp) or multiCastDet then
237	                  -- Check if server engine(s) is enabled
238	                  if (SERVER_EN_G = true) then
239	                     for i in (SERVER_SIZE_G-1) downto 0 loop
240	                        -- Check if port is defined
241	                        if (v.route = NULL_S) and (rxMaster.tData(63 downto 48) = SERVER_PORTS_C(i)) then
242	                           v.route               := SERVER_S;
243	                           v.tDestServer         := toSlv(i, 8);
244	                           v.serverRemotePort(i) := rxMaster.tData(47 downto 32);
245	                           v.serverRemoteIp(i)   := r.tData(95 downto 64);
246	                           v.serverRemoteMac(i)  := r.tData(47 downto 0);
247	                        end if;
248	                     end loop;
249	                  end if;
250	                  -- Check if clients engine(s) is enabled
251	                  if (CLIENT_EN_G = true) then
252	                     for i in (CLIENT_SIZE_G-1) downto 0 loop
253	                        -- Check if port is defined
254	                        if (v.route = NULL_S) and (rxMaster.tData(63 downto 48) = CLIENT_PORTS_C(i)) then
255	                           v.route                   := CLIENT_S;
256	                           v.tDestClient             := toSlv(i, 8);
257	                           v.clientRemoteDetValid(i) := '1';
258	                           v.clientRemoteDetIp(i)    := rxMaster.tData(95 downto 64);
259	                        end if;
260	                     end loop;
261	                  end if;
262	               end if;
263	               -- Check if DHCP engine is enabled and DHCP packet
264	               if (DHCP_G = true) and (rxMaster.tData(47 downto 32) = DHCP_SPORT) and (rxMaster.tData(63 downto 48) = DHCP_CPORT) then
265	                  v.route := DHCP_S;
266	               end if;
267	               -- Get the UDP length = UDP HDR + UDP data
268	               v.byteCnt(15 downto 8) := rxMaster.tData(71 downto 64);
269	               v.byteCnt(7 downto 0)  := rxMaster.tData(79 downto 72);
270	               -- Remove the 8 byte UDP header
271	               v.byteCnt              := v.byteCnt - 8;
272	               -- Remove the RoCEv2 iCRC
273	               if rxMaster.tData(63 downto 48) = x"B712" then
274	                  v.byteCnt := v.byteCnt - 4;
275	               end if;
276	               -- Track the leftovers
277	               v.tData(31 downto 0) := rxMaster.tData(127 downto 96);
278	               -- Set the flag
279	               v.sof                := '1';
280	               -- Check if localhost
281	               if (localIp = r.tData(95 downto 64)) then
282	                  v.localHost := '1';
283	               else
284	                  v.localHost := '0';
285	               end if;
286	               -- Check for non-NULL route type
287	               if (v.route /= NULL_S) then
288	                  -- Check for leftovers
289	                  if (rxMaster.tLast = '1') or (v.byteCnt <= 4) then
290	                     -- Next state
291	                     v.state := LAST_S;
292	                  else
293	                     -- Next state
294	                     v.state := MOVE_S;
295	                  end if;
296	               else
297	                  -- Next state
298	                  v.state := IDLE_S;
299	               end if;
300	            end if;
301	         ----------------------------------------------------------------------
302	         when MOVE_S =>
303	            -- Check the route type
304	            case r.route is
305	               ----------------------------------------------------------------------
306	               when SERVER_S =>
307	                  -- Check if ready to move data
308	                  if (rxMaster.tValid = '1') and (v.serverMaster.tValid = '0') then
309	                     -- Accept the data
310	                     v.rxSlave.tReady                        := '1';
311	                     -- Move the data
312	                     v.serverMaster.tValid                   := '1';
313	                     v.serverMaster.tDest                    := r.tDestServer;
314	                     v.serverMaster.tData(31 downto 0)       := r.tData(31 downto 0);
315	                     v.serverMaster.tData(127 downto 32)     := rxMaster.tData(95 downto 0);
316	                     ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.serverMaster, r.sof);
317	                     -- Track the leftovers
318	                     v.tData(31 downto 0)                    := rxMaster.tData(127 downto 96);
319	                     -- Reset the flag
320	                     v.sof                                   := '0';
321	                     -- Decrement the counter
322	                     v.byteCnt                               := r.byteCnt - 16;
323	                     -- Check for tLast or the byte counter
324	                     if (rxMaster.tLast = '1') or (r.byteCnt <= 16) or (v.byteCnt <= 4) then
325	                        -- Check if not localhost
326	                        if (r.localHost = '0') then
327	                           -- Check for leftovers
328	                           if (v.byteCnt <= 4) and (r.byteCnt /= 16) then
329	                              -- Next state
330	                              v.state := LAST_S;
331	                           else
332	                              -- Terminate the packet
333	                              v.serverMaster.tKeep := genTKeep(conv_integer(r.byteCnt));
334	                              v.serverMaster.tLast := '1';
335	                              -- Next state
336	                              v.state              := IDLE_S;
337	                           end if;
338	                        else
339	                           -- Else localhost communication
340	                           if (rxMaster.tKeep(15 downto 12) /= 0) then
341	                              v.byteCnt := (x"00" & "000" & onesCount(x"000" & rxMaster.tKeep(15 downto 12)));
342	                              -- Next state
343	                              v.state   := LAST_S;
344	                           else
345	                              v.serverMaster.tKeep(15 downto 0) := rxMaster.tKeep(11 downto 0) & x"F";
346	                              v.serverMaster.tLast              := '1';
347	                              -- Next state
348	                              v.state                           := IDLE_S;
349	                           end if;
350	                        end if;
351	                     end if;
352	                  end if;
353	               ----------------------------------------------------------------------
354	               when CLIENT_S =>
355	                  -- Check if ready to move data
356	                  if (rxMaster.tValid = '1') and (v.clientMaster.tValid = '0') then
357	                     -- Accept the data
358	                     v.rxSlave.tReady                        := '1';
359	                     -- Move the data
360	                     v.clientMaster.tValid                   := '1';
361	                     v.clientMaster.tDest                    := r.tDestClient;
362	                     v.clientMaster.tData(31 downto 0)       := r.tData(31 downto 0);
363	                     v.clientMaster.tData(127 downto 32)     := rxMaster.tData(95 downto 0);
364	                     ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.clientMaster, r.sof);
365	                     -- Track the leftovers
366	                     v.tData(31 downto 0)                    := rxMaster.tData(127 downto 96);
367	                     -- Reset the flag
368	                     v.sof                                   := '0';
369	                     -- Decrement the counter
370	                     v.byteCnt                               := r.byteCnt - 16;
371	                     -- Check for tLast or the byte counter
372	                     if (rxMaster.tLast = '1') or (r.byteCnt <= 16) or (v.byteCnt <= 4) then
373	                        -- Check if not localhost
374	                        if (r.localHost = '0') then
375	                           -- Check for leftovers
376	                           if (v.byteCnt <= 4) and (r.byteCnt /= 16) then
377	                              -- Next state
378	                              v.state := LAST_S;
379	                           else
380	                              -- Terminate the packet
381	                              v.clientMaster.tKeep := genTKeep(conv_integer(r.byteCnt));
382	                              v.clientMaster.tLast := '1';
383	                              -- Next state
384	                              v.state              := IDLE_S;
385	                           end if;
386	                        else
387	                           -- Else localhost communication
388	                           if (rxMaster.tKeep(15 downto 12) /= 0) then
389	                              v.byteCnt := (x"00" & "000" & onesCount(x"000" & rxMaster.tKeep(15 downto 12)));
390	                              -- Next state
391	                              v.state   := LAST_S;
392	                           else
393	                              v.clientMaster.tKeep(15 downto 0) := rxMaster.tKeep(11 downto 0) & x"F";
394	                              v.clientMaster.tLast              := '1';
395	                              -- Next state
396	                              v.state                           := IDLE_S;
397	                           end if;
398	                        end if;
399	                     end if;
400	                  end if;
401	               ----------------------------------------------------------------------
402	               when DHCP_S =>
403	                  -- Check if ready to move data
404	                  if (rxMaster.tValid = '1') and (v.dhcpMaster.tValid = '0') then
405	                     -- Accept the data
406	                     v.rxSlave.tReady                        := '1';
407	                     -- Move the data
408	                     v.dhcpMaster.tValid                     := '1';
409	                     v.dhcpMaster.tData(31 downto 0)         := r.tData(31 downto 0);
410	                     v.dhcpMaster.tData(127 downto 32)       := rxMaster.tData(95 downto 0);
411	                     ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.dhcpMaster, r.sof);
412	                     -- Track the leftovers
413	                     v.tData(31 downto 0)                    := rxMaster.tData(127 downto 96);
414	                     -- Reset the flag
415	                     v.sof                                   := '0';
416	                     -- Decrement the counter
417	                     v.byteCnt                               := r.byteCnt - 16;
418	                     -- Check for tLast or the byte counter
419	                     if (rxMaster.tLast = '1') or (r.byteCnt <= 16) or (v.byteCnt <= 4) then
420	                        -- Check for leftovers
421	                        if (v.byteCnt <= 4) and (r.byteCnt /= 16) then
422	                           -- Next state
423	                           v.state := LAST_S;
424	                        else
425	                           -- Terminate the packet
426	                           v.dhcpMaster.tKeep := genTKeep(conv_integer(r.byteCnt));
427	                           v.dhcpMaster.tLast := '1';
428	                           -- Next state
429	                           v.state            := IDLE_S;
430	                        end if;
431	                     end if;
432	                  end if;
433	               ----------------------------------------------------------------------
434	               when NULL_S =>
435	                  -- Next state
436	                  v.state := IDLE_S;
437	            ----------------------------------------------------------------------
438	            end case;
439	         ----------------------------------------------------------------------
440	         when LAST_S =>
441	            -- Check the route type
442	            case r.route is
443	               ----------------------------------------------------------------------
444	               when SERVER_S =>
445	                  -- Check if ready to move data
446	                  if (v.serverMaster.tValid = '0') then
447	                     -- Move the data
448	                     v.serverMaster.tValid              := '1';
449	                     v.serverMaster.tDest               := r.tDestServer;
450	                     v.serverMaster.tData(127 downto 0) := r.tData;
451	                     v.serverMaster.tKeep               := genTKeep(conv_integer(r.byteCnt));
452	                     v.serverMaster.tLast               := '1';
453	                     ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.serverMaster, r.sof);
454	                     -- Next state
455	                     v.state                            := IDLE_S;
456	                  end if;
457	               ----------------------------------------------------------------------
458	               when CLIENT_S =>
459	                  -- Check if ready to move data
460	                  if (v.clientMaster.tValid = '0') then
461	                     -- Move the data
462	                     v.clientMaster.tValid              := '1';
463	                     v.clientMaster.tDest               := r.tDestClient;
464	                     v.clientMaster.tData(127 downto 0) := r.tData;
465	                     v.clientMaster.tKeep               := genTKeep(conv_integer(r.byteCnt));
466	                     v.clientMaster.tLast               := '1';
467	                     ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.clientMaster, r.sof);
468	                     -- Next state
469	                     v.state                            := IDLE_S;
470	                  end if;
471	               ----------------------------------------------------------------------
472	               when DHCP_S =>
473	                  -- Check if ready to move data
474	                  if (v.dhcpMaster.tValid = '0') then
475	                     -- Move the data
476	                     v.dhcpMaster.tValid              := '1';
477	                     v.dhcpMaster.tData(127 downto 0) := r.tData;
478	                     v.dhcpMaster.tKeep               := genTKeep(conv_integer(r.byteCnt));
479	                     v.dhcpMaster.tLast               := '1';
480	                     ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.dhcpMaster, r.sof);
481	                     -- Next state
482	                     v.state                          := IDLE_S;
483	                  end if;
484	               ----------------------------------------------------------------------
485	               when NULL_S =>
486	                  -- Next state
487	                  v.state := IDLE_S;
488	            ----------------------------------------------------------------------
489	            end case;
490	      ----------------------------------------------------------------------
491	      end case;
492	
493	      -- Combinatorial outputs before the reset
494	      rxSlave <= v.rxSlave;
495	
496	      -- Reset
497	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
498	         v := REG_INIT_C;
499	      end if;
500	
501	      -- Register the variable for next clock cycle
502	      rin <= v;
503	
504	      -- Registered Outputs
505	      serverRemotePort     <= r.serverRemotePort;
506	      serverRemoteIp       <= r.serverRemoteIp;
507	      serverRemoteMac      <= r.serverRemoteMac;
508	      clientRemoteDetValid <= r.clientRemoteDetValid;
509	      clientRemoteDetIp    <= r.clientRemoteDetIp;
510	
511	   end process comb;
512	
513	   seq : process (clk, rst) is
514	   begin
515	      if (RST_ASYNC_G and rst = RST_POLARITY_G) then
516	         r <= REG_INIT_C after TPD_G;
517	      elsif rising_edge(clk) then
518	         r <= rin after TPD_G;
519	      end if;
520	   end process seq;
521	
522	   U_Servers : entity surf.AxiStreamDeMux
523	      generic map (
524	         TPD_G          => TPD_G,
525	         RST_POLARITY_G => RST_POLARITY_G,
526	         RST_ASYNC_G    => RST_ASYNC_G,
527	         PIPE_STAGES_G  => 1,
528	         NUM_MASTERS_G  => SERVER_SIZE_G)
529	      port map (
530	         -- Clock and reset
531	         axisClk      => clk,
532	         axisRst      => rst,
533	         -- Slave
534	         sAxisMaster  => r.serverMaster,
535	         sAxisSlave   => serverSlave,
536	         -- Masters
537	         mAxisMasters => obServerMasters,
538	         mAxisSlaves  => obServerSlaves);
539	
540	   U_Clients : entity surf.AxiStreamDeMux
541	      generic map (
542	         TPD_G          => TPD_G,
543	         RST_POLARITY_G => RST_POLARITY_G,
544	         RST_ASYNC_G    => RST_ASYNC_G,
545	         PIPE_STAGES_G  => 1,
546	         NUM_MASTERS_G  => CLIENT_SIZE_G)
547	      port map (
548	         -- Clock and reset
549	         axisClk      => clk,
550	         axisRst      => rst,
551	         -- Slave
552	         sAxisMaster  => r.clientMaster,
553	         sAxisSlave   => clientSlave,
554	         -- Masters
555	         mAxisMasters => obClientMasters,
556	         mAxisSlaves  => obClientSlaves);
557	
558	   U_Dhcp : entity surf.AxiStreamPipeline
559	      generic map (
560	         TPD_G          => TPD_G,
561	         RST_POLARITY_G => RST_POLARITY_G,
562	         RST_ASYNC_G    => RST_ASYNC_G,
563	         PIPE_STAGES_G  => 0)
564	      port map (
565	         axisClk     => clk,
566	         axisRst     => rst,
567	         sAxisMaster => r.dhcpMaster,
568	         sAxisSlave  => dhcpSlave,
569	         mAxisMaster => ibDhcpMaster,
570	         mAxisSlave  => ibDhcpSlave);
571	
572	end rtl;
573

