14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiStreamPkg.all;
24	
25	entity RawEthFramer is
26	   generic (
27	      TPD_G      : time             := 1 ns;
28	      ETH_TYPE_G : slv(15 downto 0) := x"0010");  --  0x1000 (big-Endian configuration)
29	   port (
30	      -- Local Configurations
31	      localMac    : in  slv(47 downto 0);         --  big-Endian configuration
32	      remoteMac   : in  slv(47 downto 0);         --  big-Endian configuration
33	      tDest       : out slv(7 downto 0);
34	      -- Interface to Ethernet Media Access Controller (MAC)
35	      obMacMaster : in  AxiStreamMasterType;
36	      obMacSlave  : out AxiStreamSlaveType;
37	      ibMacMaster : out AxiStreamMasterType;
38	      ibMacSlave  : in  AxiStreamSlaveType;
39	      -- Interface to Application engine(s)
40	      ibAppMaster : out AxiStreamMasterType;
41	      ibAppSlave  : in  AxiStreamSlaveType;
42	      obAppMaster : in  AxiStreamMasterType;
43	      obAppSlave  : out AxiStreamSlaveType;
44	      -- Clock and Reset
45	      clk         : in  sl;
46	      rst         : in  sl);
47	end RawEthFramer;
48	
49	architecture rtl of RawEthFramer is
50	
51	   type StateType is (
52	      IDLE_S,
53	      RX_S,
54	      TX_S);
55	
56	   type RegType is record
57	      rxAck : sl;
58	      txAck : sl;
59	      rxMac : slv(47 downto 0);
60	      txMac : slv(47 downto 0);
61	      rdEn  : sl;
62	      tDest : slv(7 downto 0);
63	      state : StateType;
64	   end record RegType;
65	   constant REG_INIT_C : RegType := (
66	      rxAck => '0',
67	      txAck => '0',
68	      rxMac => (others => '0'),
69	      txMac => (others => '0'),
70	      rdEn  => '0',
71	      tDest => (others => '0'),
72	      state => IDLE_S);
73	
74	   signal r   : RegType := REG_INIT_C;
75	   signal rin : RegType;
76	
77	   signal rxReq  : sl;
78	   signal txReq  : sl;
79	   signal rxDest : slv(7 downto 0);
80	   signal txDest : slv(7 downto 0);
81	   signal rxAck  : sl;
82	   signal txAck  : sl;
83	   signal rxMac  : slv(47 downto 0);
84	   signal txMac  : slv(47 downto 0);
85	
86	   -- attribute dont_touch           : string;
87	   -- attribute dont_touch of r      : signal is "TRUE";
88	
89	begin
90	
