116	      port map (
117	         -- Local Configurations
118	         localMac    => localMac,
119	         remoteMac   => rxMac,
120	         tDest       => rxDest,
121	         req         => rxReq,
122	         ack         => rxAck,
123	         -- Interface to Ethernet Media Access Controller (MAC)
