141	      v.txAck := '0';
142	
143	      -- shift Register
144	      v.rdEn := '0';
145	
146	      -- State Machine
147	      case r.state is
148	         ----------------------------------------------------------------------
149	         when IDLE_S =>
150	            -- Check for RX request
151	            if (r.rxAck = '0') and (rxReq = '1') then
152	               -- Set the flag
153	               v.rdEn  := '1';
154	               -- Set the data bus
155	               v.tDest := rxDest;
156	               -- Next state
157	               v.state := RX_S;
158	            elsif (r.txAck = '0') and (txReq = '1') then
159	               -- Set the flag
160	               v.rdEn  := '1';
161	               -- Set the data bus
162	               v.tDest := txDest;
163	               -- Next state
164	               v.state := TX_S;
165	            end if;
