167	         when RX_S =>
168	            -- Check if data is ready
169	            if r.rdEn = '0' then
170	               -- Set the flag
171	               v.rxAck := '1';
172	               -- Set the data bus
173	               v.rxMac := remoteMac;
174	               -- Next state
175	               v.state := IDLE_S;
176	            end if;
177	         ----------------------------------------------------------------------
178	         when TX_S =>
179	            -- Check if data is ready
180	            if r.rdEn = '0' then
181	               -- Set the flag
182	               v.txAck := '1';
183	               -- Set the data bus
184	               v.txMac := remoteMac;
185	               -- Next state
186	               v.state := IDLE_S;
187	            end if;
188	      ----------------------------------------------------------------------
189	      end case;
