191	      -- Combinatorial outputs before the reset
192	      tDest <= v.tDest;
193	      rxAck <= v.rxAck;
194	      txAck <= v.txAck;
195	      rxMac <= v.rxMac;
196	      txMac <= v.txMac;
197	
198	      -- Reset
