1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: Raw L2 Ethernet Framer's TX Engine
5	-------------------------------------------------------------------------------
6	-- This file is part of 'SLAC Firmware Standard Library'.
7	-- It is subject to the license terms in the LICENSE.txt file found in the
8	-- top-level directory of this distribution and at:
9	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
10	-- No part of 'SLAC Firmware Standard Library', including this file,
11	-- may be copied, modified, propagated, or distributed except according to
12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiStreamPkg.all;
24	use surf.SsiPkg.all;
25	use surf.RawEthFramerPkg.all;
26	
27	entity RawEthFramerTx is
28	   generic (
29	      TPD_G      : time             := 1 ns;
30	      ETH_TYPE_G : slv(15 downto 0) := x"0010");  --  0x1000 (big-Endian configuration)
31	   port (
32	      -- Local Configurations
33	      localMac    : in  slv(47 downto 0);         --  big-Endian configuration
34	      remoteMac   : in  slv(47 downto 0);         --  big-Endian configuration
35	      tDest       : out slv(7 downto 0);
36	      req         : out sl;
37	      ack         : in  sl;
38	      -- Interface to Ethernet Media Access Controller (MAC)
39	      ibMacMaster : out AxiStreamMasterType;
40	      ibMacSlave  : in  AxiStreamSlaveType;
41	      -- Interface to Application engine(s)
42	      obAppMaster : in  AxiStreamMasterType;
43	      obAppSlave  : out AxiStreamSlaveType;
44	      -- Clock and Reset
45	      clk         : in  sl;
46	      rst         : in  sl);
47	end RawEthFramerTx;
48	
49	architecture rtl of RawEthFramerTx is
50	
51	   type StateType is (
52	      IDLE_S,
53	      TDEST_S,
54	      CACHE_S,
55	      MOVE_S);
56	
57	   type RegType is record
58	      bcf         : sl;
59	      req         : sl;
60	      tDest       : slv(7 downto 0);
61	      wen         : sl;
62	      wrAddr      : slv(2 downto 0);
63	      wrData      : slv(63 downto 0);
64	      rdAddr      : slv(15 downto 0);
65	      minByteCnt  : natural range 0 to 64;
66	      eof         : sl;
67	      eofe        : sl;
68	      obAppSlave  : AxiStreamSlaveType;
69	      ibMacMaster : AxiStreamMasterType;
70	      state       : StateType;
71	   end record RegType;
72	   constant REG_INIT_C : RegType := (
73	      bcf         => '0',
74	      req         => '0',
75	      tDest       => (others => '0'),
76	      wen         => '0',
77	      wrAddr      => (others => '0'),
78	      wrData      => (others => '0'),
79	      rdAddr      => (others => '0'),
80	      minByteCnt  => 0,
81	      eof         => '0',
82	      eofe        => '0',
83	      obAppSlave  => AXI_STREAM_SLAVE_INIT_C,
84	      ibMacMaster => AXI_STREAM_MASTER_INIT_C,
85	      state       => IDLE_S);
86	
87	   signal r   : RegType := REG_INIT_C;
88	   signal rin : RegType;
89	
90	   signal rdData : slv(63 downto 0);
91	
92	   -- attribute dont_touch           : string;
93	   -- attribute dont_touch of r      : signal is "TRUE";
94	   -- attribute dont_touch of rdData : signal is "TRUE";
95	
96	begin
97	
98	   U_MinEthCache : entity surf.LutRam
99	      generic map (
100	         TPD_G        => TPD_G,
101	         NUM_PORTS_G  => 2,
102	         REG_EN_G     => false,         -- 1 cycle read
103	         DATA_WIDTH_G => 64,
104	         ADDR_WIDTH_G => 3)
105	      port map (
106	         -- Port A (Read/Write)
107	         clka  => clk,
108	         wea   => r.wen,
109	         addra => r.wrAddr,
110	         dina  => r.wrData,
111	         -- Port B (Read Only)
112	         clkb  => clk,
113	         addrb => r.rdAddr(2 downto 0),
114	         doutb => rdData);
115	
116	   comb : process (ack, ibMacSlave, localMac, obAppMaster, r, rdData,
117	                   remoteMac, rst) is
118	      variable v     : RegType;
119	      variable i     : natural;
120	      variable tKeep : slv(15 downto 0);
121	   begin
122	      -- Latch the current value
123	      v := r;
124	
125	      -- Reset the flags
126	      v.wen        := '0';
127	      v.obAppSlave := AXI_STREAM_SLAVE_INIT_C;
128	      if ibMacSlave.tReady = '1' then
129	         v.ibMacMaster.tValid := '0';
130	         v.ibMacMaster.tLast  := '0';
131	         v.ibMacMaster.tUser  := (others => '0');
132	         v.ibMacMaster.tKeep  := resize(x"00FF", AXI_STREAM_MAX_TKEEP_WIDTH_C);
133	      end if;
134	
135	      -- Update variables
136	      tKeep := x"00" & obAppMaster.tKeep(7 downto 0);
137	
138	      -- State Machine
139	      case r.state is
140	         ----------------------------------------------------------------------
141	         when IDLE_S =>
142	            -- Check if ready to move data
143	            if (obAppMaster.tValid = '1') and (v.ibMacMaster.tValid = '0') then
144	               -- Check for SOF
145	               if (ssiGetUserSof(RAW_ETH_CONFIG_INIT_C, obAppMaster) = '1') then
146	                  -- Latch the routing information
147	                  v.bcf   := ssiGetUserBcf(RAW_ETH_CONFIG_INIT_C, obAppMaster);
148	                  v.tDest := obAppMaster.tDest;
149	                  -- Set the flag
150	                  v.req   := not(v.bcf);
151	                  -- Next state
152	                  v.state := TDEST_S;
153	               else
154	                  -- Accept the data
155	                  v.obAppSlave.tReady := '1';
156	               end if;
157	            end if;
158	         ----------------------------------------------------------------------
159	         when TDEST_S =>
160	            if (ack = '1') or (r.bcf = '1') then
161	               -- Accept the data
162	               v.obAppSlave.tReady := '1';
163	               -- Reset the flag
164	               v.req               := '0';
165	               -- Check for valid DST MAC or broadcast
166	               if (remoteMac /= 0) or (r.bcf = '1') then
167	                  -- Write to cache
168	                  v.wen    := '1';
169	                  v.wrAddr := toSlv(2, 3);
170	                  for i in 7 downto 0 loop
171	                     if tKeep(i) = '1' then
172	                        v.wrData(7+(8*i) downto (8*i)) := obAppMaster.tData(7+(8*i) downto (8*i));
173	                     else
174	                        v.wrData(7+(8*i) downto (8*i)) := x"00";  -- zero padding
175	                     end if;
176	                  end loop;
177	                  -- Update the min. ETH Byte counter
178	                  v.minByteCnt := 16 + getTKeep(tKeep, RAW_ETH_CONFIG_INIT_C);  -- include header offset
179	                  -- Check for tLast
180	                  if obAppMaster.tLast = '1' then
181	                     -- Set EOF
182	                     v.eof   := '1';
183	                     -- Get EOFE
184	                     v.eofe  := ssiGetUserEofe(RAW_ETH_CONFIG_INIT_C, obAppMaster);
185	                     -- Next state
186	                     v.state := MOVE_S;
187	                  else
188	                     -- Next state
189	                     v.state := CACHE_S;
190	                  end if;
191	                  ------------------
192	                  -- Write HDR[0] --
193	                  ------------------
194	                  -- Set the SOF
195	                  ssiSetUserSof(RAW_ETH_CONFIG_INIT_C, v.ibMacMaster, '1');
196	                  -- Move the data
197	                  v.ibMacMaster.tValid := '1';
198	                  -- Check for broadcast message
199	                  if (r.bcf = '1') then
200	                     v.ibMacMaster.tData(47 downto 0) := (others => '1');
201	                  else
202	                     v.ibMacMaster.tData(47 downto 0) := remoteMac;
203	                  end if;
204	                  v.ibMacMaster.tData(63 downto 48) := localMac(15 downto 0);
205	                  -- Preset the address
206	                  v.rdAddr                          := toSlv(1, 16);
207	               else
208	                  -- Next state
209	                  v.state := IDLE_S;
210	               end if;
211	            end if;
212	         ----------------------------------------------------------------------
213	         when CACHE_S =>
214	            -- Check if ready to move data
215	            if (obAppMaster.tValid = '1') and (v.ibMacMaster.tValid = '0') then
216	               -- Accept the data
217	               v.obAppSlave.tReady := '1';
218	               -- Write to cache
219	               v.wen               := '1';
220	               v.wrAddr            := r.wrAddr + 1;
221	               for i in 7 downto 0 loop
222	                  if tKeep(i) = '1' then
223	                     v.wrData(7+(8*i) downto (8*i)) := obAppMaster.tData(7+(8*i) downto (8*i));
224	                  else
225	                     v.wrData(7+(8*i) downto (8*i)) := x"00";  -- zero padding
226	                  end if;
227	               end loop;
228	               -- Update the min. ETH Byte counter
229	               v.minByteCnt := r.minByteCnt + getTKeep(tKeep, RAW_ETH_CONFIG_INIT_C);
230	               -- Check for tLast
231	               if obAppMaster.tLast = '1' then
232	                  -- Set EOF
233	                  v.eof   := '1';
234	                  -- Get EOFE
235	                  v.eofe  := ssiGetUserEofe(RAW_ETH_CONFIG_INIT_C, obAppMaster);
236	                  -- Next state
237	                  v.state := MOVE_S;
238	               elsif r.wrAddr = 6 then
239	                  -- Reset EOF
240	                  v.eof   := '0';
241	                  -- Next state
242	                  v.state := MOVE_S;
243	               end if;
244	               -- Check if next state is MOVE_S
245	               if v.state = MOVE_S then
246	                  ------------------
247	                  -- Write HDR[1] --
248	                  ------------------
249	                  -- Move the data
250	                  v.ibMacMaster.tValid              := '1';
251	                  v.ibMacMaster.tData(31 downto 0)  := localMac(47 downto 16);
252	                  v.ibMacMaster.tData(47 downto 32) := ETH_TYPE_G;
253	                  -- Check for eof during caching
254	                  if v.eof = '0' then
255	                     v.ibMacMaster.tData(54 downto 48) := (others => '0');
256	                  else
257	                     v.ibMacMaster.tData(54 downto 48) := toSlv(v.minByteCnt, 7);
258	                  end if;
259	                  -- Check for broadcast message
260	                  if (r.bcf = '1') then
261	                     v.ibMacMaster.tData(63 downto 55) := (others => '1');
262	                  else
263	                     v.ibMacMaster.tData(63 downto 55) := r.tDest & '0';
264	                  end if;
265	                  -- Preset the address
266	                  v.rdAddr := toSlv(2, 16);
267	               end if;
268	            end if;
269	         ----------------------------------------------------------------------
270	         when MOVE_S =>
271	            -- Check if ready to move data
272	            if (v.ibMacMaster.tValid = '0') then
273	               -- Increment the counter
274	               v.rdAddr := r.rdAddr + 1;
275	               -- Check for HDR[1]
276	               if r.rdAddr = 1 then
277	                  -- Move the data
278	                  v.ibMacMaster.tValid              := '1';
279	                  v.ibMacMaster.tData(31 downto 0)  := localMac(47 downto 16);
280	                  v.ibMacMaster.tData(47 downto 32) := ETH_TYPE_G;
281	                  -- Check for eof during caching
282	                  if r.eof = '0' then
283	                     v.ibMacMaster.tData(54 downto 48) := (others => '0');
284	                  else
285	                     v.ibMacMaster.tData(54 downto 48) := toSlv(r.minByteCnt, 7);
286	                  end if;
287	                  -- Check for broadcast message
288	                  if (r.bcf = '1') then
289	                     v.ibMacMaster.tData(63 downto 55) := (others => '1');
290	                  else
291	                     v.ibMacMaster.tData(63 downto 55) := r.tDest & '0';
292	                  end if;
293	               elsif r.rdAddr(15 downto 3) = 0 then
294	                  -- Move the data
295	                  v.ibMacMaster.tValid             := '1';
296	                  v.ibMacMaster.tData(63 downto 0) := rdData;
297	                  -- Check for eof during caching
298	                  if r.eof = '1' then
299	                     -- Check for last transfer
300	                     if r.rdAddr(2 downto 0) = r.wrAddr then
301	                        -- Set EOF
302	                        v.ibMacMaster.tLast := '1';
303	                        -- Set the EOFE
304	                        ssiSetUserEofe(RAW_ETH_CONFIG_INIT_C, v.ibMacMaster, r.eofe);
305	                        -- Next state
306	                        v.state             := IDLE_S;
307	                     end if;
308	                  end if;
309	               elsif (obAppMaster.tValid = '1') then
310	                  -- Accept the data
311	                  v.obAppSlave.tReady              := '1';
312	                  -- Move the data
313	                  v.ibMacMaster.tValid             := '1';
314	                  v.ibMacMaster.tData(63 downto 0) := obAppMaster.tData(63 downto 0);
315	                  v.ibMacMaster.tKeep(7 downto 0)  := obAppMaster.tKeep(7 downto 0);
316	                  -- Check for tLast
317	                  if obAppMaster.tLast = '1' then
318	                     -- Set EOF
319	                     v.ibMacMaster.tLast := '1';
320	                     -- Get the EOFE
321	                     v.eofe              := ssiGetUserEofe(RAW_ETH_CONFIG_INIT_C, obAppMaster);
322	                     -- Set the EOFE
323	                     ssiSetUserEofe(RAW_ETH_CONFIG_INIT_C, v.ibMacMaster, v.eofe);
324	                     -- Next state
325	                     v.state             := IDLE_S;
326	                  end if;
327	               end if;
328	            end if;
329	      ----------------------------------------------------------------------
330	      end case;
331	
332	      -- Combinatorial outputs before the reset
333	      obAppSlave <= v.obAppSlave;
334	      tDest      <= v.tDest;
335	      req        <= v.req;
336	
337	      -- Reset
338	      if (rst = '1') then
339	         v := REG_INIT_C;
340	      end if;
341	
342	      -- Register the variable for next clock cycle
343	      rin <= v;
344	
345	      -- Registered Outputs
346	      ibMacMaster <= r.ibMacMaster;
347	
348	   end process comb;
349	
350	   seq : process (clk) is
351	   begin
352	      if rising_edge(clk) then
353	         r <= rin after TPD_G;
354	      end if;
355	   end process seq;
