14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiStreamPkg.all;
24	use surf.SsiPkg.all;
25	use surf.RawEthFramerPkg.all;
26	
27	entity RawEthFramerRx is
28	   generic (
29	      TPD_G      : time             := 1 ns;
30	      ETH_TYPE_G : slv(15 downto 0) := x"0010");  --  0x1000 (big-Endian configuration)
31	   port (
32	      -- Local Configurations
33	      localMac    : in  slv(47 downto 0);         --  big-Endian configuration
34	      remoteMac   : in  slv(47 downto 0);         --  big-Endian configuration
35	      tDest       : out slv(7 downto 0);
36	      req         : out sl;
37	      ack         : in  sl;
38	      -- Interface to Ethernet Media Access Controller (MAC)
39	      obMacMaster : in  AxiStreamMasterType;
40	      obMacSlave  : out AxiStreamSlaveType;
41	      -- Interface to Application engine(s)
42	      ibAppMaster : out AxiStreamMasterType;
43	      ibAppSlave  : in  AxiStreamSlaveType;
44	      -- Clock and Reset
45	      clk         : in  sl;
46	      rst         : in  sl);
47	end RawEthFramerRx;
48	
49	architecture rtl of RawEthFramerRx is
50	
51	   constant BC_MAC_C : slv(47 downto 0) := x"FFFFFFFFFFFF";
52	
53	   type StateType is (
54	      IDLE_S,
55	      HDR_S,
56	      TDEST_S,
57	      MOVE_S);
58	
59	   type RegType is record
60	      bcf         : sl;
61	      req         : sl;
62	      dstMac      : slv(47 downto 0);
63	      srcMac      : slv(47 downto 0);
64	      minByteCnt  : natural range 0 to 127;
65	      sof         : sl;
66	      eof         : sl;
67	      eofe        : sl;
68	      obMacSlave  : AxiStreamSlaveType;
69	      ibAppMaster : AxiStreamMasterType;
70	      state       : StateType;
71	   end record RegType;
72	   constant REG_INIT_C : RegType := (
73	      bcf         => '0',
74	      req         => '0',
75	      dstMac      => (others => '0'),
76	      srcMac      => (others => '0'),
77	      minByteCnt  => 0,
78	      sof         => '1',
79	      eof         => '0',
80	      eofe        => '0',
81	      obMacSlave  => AXI_STREAM_SLAVE_INIT_C,
82	      ibAppMaster => AXI_STREAM_MASTER_INIT_C,
83	      state       => IDLE_S);
84	
85	   signal r   : RegType := REG_INIT_C;
86	   signal rin : RegType;
87	
88	   -- attribute dont_touch             : string;
89	   -- attribute dont_touch of r        : signal is "TRUE";
90	
91	begin
92	
93	   comb : process (ack, ibAppSlave, localMac, obMacMaster, r, remoteMac, rst) is
94	      variable v : RegType;
95	   begin
96	      -- Latch the current value
97	      v := r;
98	
99	      -- Reset the flags
100	      v.obMacSlave := AXI_STREAM_SLAVE_INIT_C;
101	      if ibAppSlave.tReady = '1' then
102	         v.ibAppMaster.tValid := '0';
103	         v.ibAppMaster.tLast  := '0';
104	         v.ibAppMaster.tUser  := (others => '0');
105	         v.ibAppMaster.tKeep  := resize(x"00FF", AXI_STREAM_MAX_TKEEP_WIDTH_C);
106	      end if;
107	
108	      -- State Machine
109	      case r.state is
110	         ----------------------------------------------------------------------
111	         when IDLE_S =>
112	            -- Check for data
113	            if (obMacMaster.tValid = '1') then
114	               -- Accept the data
115	               v.obMacSlave.tReady   := '1';
116	               -- Latch the DST MAC and SRC MAC
117	               v.dstMac              := obMacMaster.tData(47 downto 0);
118	               v.srcMac(15 downto 0) := obMacMaster.tData(63 downto 48);
119	               -- Check for SOF
120	               if (ssiGetUserSof(RAW_ETH_CONFIG_INIT_C, obMacMaster) = '1') then
121	                  -- Check the DEST MAC
122	                  if (localMac /= 0) and ((localMac = v.dstMac) or (v.dstMac = BC_MAC_C))then
123	                     -- Next state
124	                     v.state := HDR_S;
125	                  end if;
126	               end if;
127	            end if;
128	         ----------------------------------------------------------------------
129	         when HDR_S =>
130	            -- Check for data
131	            if (obMacMaster.tValid = '1') and (v.ibAppMaster.tValid = '0') then
132	               -- Accept the data
133	               v.obMacSlave.tReady    := '1';
134	               -- Latch the SRC MAC
135	               v.srcMac(47 downto 16) := obMacMaster.tData(31 downto 0);
136	               -- Latch the tDest & BC
137	               v.ibAppMaster.tDest    := obMacMaster.tData(63 downto 56);
138	               v.bcf                  := obMacMaster.tData(55);
139	               -- Get the min. byte cache count
140	               v.minByteCnt           := conv_integer(obMacMaster.tData(54 downto 48));
141	               -- Check for invalid size or invalid EtherType
142	               if (v.minByteCnt > 64) or (obMacMaster.tData(47 downto 32) /= ETH_TYPE_G) then
143	                  -- Next state
144	                  v.state := IDLE_S;
145	               -- Check for invalid size
146	               elsif (v.minByteCnt /= 0) and (v.minByteCnt <= 16) then
147	                  -- Next state
148	                  v.state := IDLE_S;
149	               -- Check for invalid broadcast message
150	               elsif (v.bcf = '1') and ((v.ibAppMaster.tDest /= x"FF") or (r.dstMac /= BC_MAC_C)) then
151	                  -- Next state
152	                  v.state := IDLE_S;
153	               else
154	                  -- Set the flag
155	                  v.req   := not(v.bcf);
156	                  -- Next state
157	                  v.state := TDEST_S;
158	               end if;
159	            end if;
160	         ----------------------------------------------------------------------
161	         when TDEST_S =>
162	            if (ack = '1') or (r.bcf = '1') then
163	               -- Reset the flag
164	               v.sof := '1';
165	               -- Update EOF flag
166	               if r.minByteCnt = 0 then
167	                  -- Reset the flag
168	                  v.eof := '0';
169	               else
170	                  -- Set the flag
171	                  v.eof        := '1';
172	                  -- Remove the header offset
173	                  v.minByteCnt := r.minByteCnt - 16;
174	               end if;
175	               -- Check for valid SRC MAC or broadcast
176	               if ((remoteMac /= 0) and (remoteMac = r.srcMac)) or (r.bcf = '1') then
177	                  -- Next state
178	                  v.state := MOVE_S;
179	               else
180	                  -- Next state
181	                  v.state := IDLE_S;
182	               end if;
183	            end if;
184	         ----------------------------------------------------------------------
185	         when MOVE_S =>
186	            -- Check if ready to move data
187	            if (obMacMaster.tValid = '1') and (v.ibAppMaster.tValid = '0') then
188	               -- Accept the data
189	               v.obMacSlave.tReady              := '1';
190	               -- Move the data
191	               v.ibAppMaster.tValid             := '1';
192	               v.ibAppMaster.tData(63 downto 0) := obMacMaster.tData(63 downto 0);
193	               v.ibAppMaster.tKeep(7 downto 0)  := obMacMaster.tKeep(7 downto 0);
194	               -- Check for SOF
195	               if r.sof = '1' then
196	                  -- Reset the flag
197	                  v.sof := '0';
198	                  -- Set the SOF and BCF
199	                  ssiSetUserSof(RAW_ETH_CONFIG_INIT_C, v.ibAppMaster, '1');
200	                  ssiSetUserBcf(RAW_ETH_CONFIG_INIT_C, v.ibAppMaster, r.bcf);
201	               end if;
202	               -- Get EOFE
203	               v.eofe := ssiGetUserEofe(RAW_ETH_CONFIG_INIT_C, obMacMaster);
204	               -- Check for tLast
205	               if obMacMaster.tLast = '1' then
206	                  -- Set EOF
207	                  v.ibAppMaster.tLast := '1';
208	                  -- Set the EOFE
209	                  ssiSetUserEofe(RAW_ETH_CONFIG_INIT_C, v.ibAppMaster, v.eofe);
210	                  -- Next state
211	                  v.state             := IDLE_S;
212	               end if;
213	               -- Check if TX engine had min. ETH cache
214	               if r.eof = '1' then
215	                  -- Check for last transfer
216	                  if (r.minByteCnt <= 8) then
217	                     -- Update tKeep
218	                     v.ibAppMaster.tKeep := genTKeep(r.minByteCnt);
219	                     -- Set EOF
220	                     v.ibAppMaster.tLast := '1';
221	                     -- Set the EOFE
222	                     ssiSetUserEofe(RAW_ETH_CONFIG_INIT_C, v.ibAppMaster, v.eofe);
223	                     -- Next state
224	                     v.state             := IDLE_S;
225	                  else
226	                     -- Decrement the counter
227	                     v.minByteCnt := r.minByteCnt - 8;
228	                  end if;
229	               end if;
230	            end if;
231	      ----------------------------------------------------------------------
232	      end case;
233	
234	      -- Combinatorial outputs before the reset
235	      obMacSlave <= v.obMacSlave;
236	      tDest      <= v.ibAppMaster.tDest;
237	      req        <= v.req;
238	
239	      -- Reset
240	      if (rst = '1') then
241	         v := REG_INIT_C;
242	      end if;
243	
244	      -- Register the variable for next clock cycle
245	      rin <= v;
246	
247	      -- Registered Outputs
248	      ibAppMaster <= r.ibAppMaster;
249	
250	   end process comb;
